#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x1, y1, x2, y2;
        scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        if (x1 == x2) {
            if (y1 < y2) printf("up\n");
            else printf("down\n");
        } else if (y1 == y2) {
            if (x1 < x2) printf("right\n");
            else printf("left\n");
        } else {
            printf("sad\n");
        }
    }
    return 0;
}

